package org.mockito.internal.invocation.steps;

import cucumber.api.java.en.Given;
import cucumber.api.java.en.Then;
import cucumber.api.java.en.When;
import org.mockito.Mock;
import org.mockito.internal.matchers.AnyVararg;
import org.mockito.internal.matchers.LocalizedMatcher;
import org.mockito.internal.invocation.InvocationMatcher;
import org.mockito.invocation.Invocation;
import org.mockito.internal.invocation.InvocationBuilder;
import org.mockitousage.IMethods;
import org.mockito.MockitoAnnotations;
import java.util.Collections;
import java.util.List;
import static java.util.Arrays.asList;
import static org.junit.Assert.*;

public class StepDefs {

    @Mock private IMethods mock;
    private Invocation invocation;
    private InvocationMatcher invocationMatcher;
    private Exception caughtException;

    public StepDefs() {
        MockitoAnnotations.initMocks(this);
    }

    @Given("^a mock object with a method accepting varargs arguments$")
    public void a_mock_object_with_a_method_accepting_varargs_arguments() throws Throwable {
        // mock is already initialized
    }

    @Given("^the method is invoked with an empty varargs array$")
    public void the_method_is_invoked_with_an_empty_varargs_array() throws Throwable {
        // Constructing invocation for varargs() which corresponds to varargs(new Object[0])
        // The argument passed to the method is an empty Object array.
        invocation = new InvocationBuilder().mock(mock).method("varargs").args(new Object[]{new Object[]{}}).toInvocation();
    }

    @When("^an InvocationMatcher is created for this invocation using an AnyVararg matcher$")
    public void an_InvocationMatcher_is_created_for_this_invocation_using_an_AnyVararg_matcher() throws Throwable {
        try {
            invocationMatcher = new InvocationMatcher(invocation, (List) asList(new LocalizedMatcher(AnyVararg.ANY_VARARG)));
        } catch (Exception e) {
            caughtException = e;
        }
    }

    @Then("^the InvocationMatcher should be able to capture arguments from the invocation without errors$")
    public void the_InvocationMatcher_should_be_able_to_capture_arguments_from_the_invocation_without_errors() throws Throwable {
        if (caughtException != null) {
             fail("Exception thrown during creation: " + caughtException.getMessage());
        }
        try {
            invocationMatcher.captureArgumentsFrom(invocation);
        } catch (Exception e) {
            e.printStackTrace();
            fail("Should not have thrown exception but threw: " + e);
        }
    }
}
